import type { MealType } from '@motivation/shared';
import { appNow } from '@motivation/shared';
import { getAppTimeZone } from '../../services/app-timezone.service.js';

export function activityIcon(type: string): string {
    switch (type) {
        // Snake-cased Strava sport_types (story 142).
        case 'running': return '🏃';
        case 'cycling': return '🚴';
        case 'swimming': return '🏊';
        case 'walking': return '🚶';
        case 'hiking': return '🥾';
        case 'tennis': return '🎾';
        case 'ice_skate': return '⛸️';
        case 'alpine_ski': return '⛷️';
        case 'hiit': return '🔥';
        case 'weight_training': return '🏋️';
        // Legacy values still present in historical rows pre-story-142.
        case 'gym': return '🏋️';
        case 'ice-skating': return '⛸️';
        default: return '💪';
    }
}

/** Compact duration for chips/summaries: 45 → '45m', 90 → '1h30m', 120 → '2h'. Empty for 0/undefined. */
export function formatDurationMinutes(minutes?: number): string {
    if (!minutes) return '';
    if (minutes >= 60) {
        const h = Math.floor(minutes / 60);
        const m = minutes % 60;
        return m > 0 ? `${h}h${m}m` : `${h}h`;
    }
    return `${minutes}m`;
}

export function getDefaultMealType(hour: number = appNow(getAppTimeZone()).hour): MealType {
    if (hour < 11) return 'Breakfast';
    if (hour < 15) return 'Lunch';
    if (hour < 21) return 'Dinner';
    return 'Snacks';
}
